  48→function filterSections(sections: SectionData[], query: string): SectionData[] {
  49→  if (!query) return sections;
  50→  const lower = query.toLowerCase();
  51→  return sections
  52→    .map(section => ({
  53→      ...section,
  54→      items: section.items.filter(
  55→        item =>
  56→          item.title.toLowerCase().includes(lower) ||
  57→          item.subtitle?.toLowerCase().includes(lower),
  58→      ),
  59→    }))
  60→    .filter(section => section.items.length > 0);
  61→}
  62→
  63→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
  64→  if (!query) return colors;
  65→  const lower = query.toLowerCase();
  66→  return colors.filter(
  67→    c =>
  68→      c.title.toLowerCase().includes(lower) ||
  69→      c.subtitle?.toLowerCase().includes(lower),
  70→  );
  71→}
  72→
  73→function flattenItems(sections: SectionData[]): ListItemData[] {
  74→  return sections.flatMap(s => s.items);
  75→}
  76→
  77→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
  78→  switch (entry.type) {
  79→    case 'label':
  80→      return (
  81→        <DetailMetadata.Label
  82→          key={index}
  83→          title={entry.title}
  84→          text={entry.text}
  85→        />
  86→      );
  87→    case 'link':
  88→      return (
  89→        <DetailMetadata.Link
  90→          key={index}
  91→          title={entry.title}
  92→          text={entry.text}
  93→          target={entry.target}
  94→        />
  95→      );
  96→    case 'tag-list':
  97→      return (
  98→        <DetailMetadata.TagList key={index} title={entry.title}>
  99→          {entry.tags.map(tag => (
 100→            <DetailMetadata.Tag
 101→              key={tag.text}
 102→              text={tag.text}
 103→              color={tag.color}
 104→            />
 105→          ))}
 106→        </DetailMetadata.TagList>
 107→      );
 108→    case 'separator':
 109→      return <DetailMetadata.Separator key={index} />;
 110→  }
 111→}
