 259→function CreateSnippetView({ onSubmit }: CreateSnippetViewProps) {
 260→  const [snippetForm, setSnippetForm] =
 261→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
 262→  const [formErrors, setFormErrors] = useState<
 263→    Partial<Record<keyof SnippetFormState, string>>
 264→  >({});
 265→
 266→  const handleSubmit = useCallback(() => {
 267→    const errors: Partial<Record<keyof SnippetFormState, string>> = {};
 268→    if (!snippetForm.name.trim()) {
 269→      errors.name = 'Name is required';
 270→    }
 271→    if (!snippetForm.snippet.trim()) {
 272→      errors.snippet = 'Snippet content is required';
 273→    }
 274→    setFormErrors(errors);
 275→    if (Object.keys(errors).length > 0) {
 276→      return;
 277→    }
 278→    onSubmit(snippetForm);
 279→  }, [
 280→    snippetForm,
 281→    onSubmit,
 282→  ]);
 283→
 284→  useEffect(() => {
 285→    function handleKeyDown(e: KeyboardEvent) {
 286→      if (e.key === 'Enter' && e.metaKey) {
 287→        e.preventDefault();
 288→        handleSubmit();
 289→      }
 290→    }
 291→    window.addEventListener('keydown', handleKeyDown);
 292→    return () => window.removeEventListener('keydown', handleKeyDown);
 293→  }, [handleSubmit]);
 294→
 295→  return (
 296→    <Form onSubmit={handleSubmit}>
 297→      <FormTextField
 298→        label="Name"
 299→        value={snippetForm.name}
 300→        onChange={v =>
 301→          setSnippetForm(prev => ({
 302→            ...prev,
 303→            name: v,
 304→          }))
 305→        }
 306→        placeholder="e.g. Email Signature"
 307→        error={formErrors.name}
 308→        autoFocus
 309→      />
 310→      <FormTextField
 311→        label="Keyword"
 312→        value={snippetForm.keyword}
 313→        onChange={v =>
 314→          setSnippetForm(prev => ({
 315→            ...prev,
 316→            keyword: v,
 317→          }))
 318→        }
 319→        placeholder="e.g. !sig"
 320→        description="Type this to expand the snippet"
 321→      />
 322→      <FormDropdown
 323→        label="Category"
 324→        value={snippetForm.category}
 325→        onChange={v =>
 326→          setSnippetForm(prev => ({
 327→            ...prev,
 328→            category: v,
 329→          }))
 330→        }
 331→        options={SNIPPET_CATEGORIES}
 332→        placeholder="Select a category"
 333→      />
 334→      <FormTagPicker
 335→        label="Tags"
 336→        value={snippetForm.tags}
 337→        onChange={v =>
 338→          setSnippetForm(prev => ({
 339→            ...prev,
 340→            tags: v,
 341→          }))
 342→        }
 343→        options={SNIPPET_TAGS}
 344→        placeholder="Add tags..."
 345→        description="Categorize your snippet with tags"
 346→      />
 347→      <FormTextArea
 348→        label="Snippet"
 349→        value={snippetForm.snippet}
 350→        onChange={v =>
 351→          setSnippetForm(prev => ({
 352→            ...prev,
 353→            snippet: v,
 354→          }))
 355→        }
 356→        placeholder="Enter your snippet content..."
 357→        error={formErrors.snippet}
 358→        rows={5}
 359→      />
 360→      <FormCheckbox
 361→        label="Share with team"
 362→        checked={snippetForm.isShared}
 363→        onChange={v =>
 364→          setSnippetForm(prev => ({
 365→            ...prev,
 366→            isShared: v,
 367→          }))
 368→        }
 369→        description="Make this snippet available to your team members"
 370→      />
 371→      <FormDatePicker
 372→        label="Expires"
 373→        value={snippetForm.expiresAt}
 374→        onChange={v =>
 375→          setSnippetForm(prev => ({
 376→            ...prev,
 377→            expiresAt: v,
 378→          }))
 379→        }
 380→        description="Optional expiration date"
 381→      />
 382→    </Form>
 383→  );
 384→}
