 427→function DetailView({ item }: { item: ListItemData }) {
 428→  const itemDetail = item.detail;
 429→  if (!itemDetail) return null;
 430→  return (
 431→    <Detail
 432→      markdown={itemDetail.markdown}
 433→      metadata={
 434→        itemDetail.metadata ? (
 435→          <DetailMetadata>
 436→            {itemDetail.metadata.map(renderMetadataEntry)}
 437→          </DetailMetadata>
 438→        ) : undefined
 439→      }
 440→    />
 441→  );
 442→}
