 444→export function App() {
 445→  const [query, setQuery] = useState('');
 446→  const [filterValue, setFilterValue] = useState('all');
 447→  const [selectedIndex, setSelectedIndex] = useState(0);
 448→  const [actionsOpen, setActionsOpen] = useState(false);
