 450→  const { items: hudItems, show: showHUD } = useHUD();
 451→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 452→  const nav = useNavigationStack<NavViewData>('Raycast');
 453→  const { push, pop } = nav;
 454→
 455→  const viewType = nav.currentEntry?.data.type ?? 'root';
 456→
 457→  const searchFilterSections: SearchDropdownSection[] = useMemo(
