 471→            label: 'Commands',
 472→            value: 'commands',
 473→          },
 474→          {
 475→            label: 'Applications',
 476→            value: 'applications',
 477→          },
 478→        ],
 479→      },
 480→    ],
 481→    [],
 482→  );
 483→
 484→  useEffect(() => {
