 535→        icon: <ClipboardHUDIcon />,
 536→        title: `Copied ${color.color}`,
 537→      });
 538→    },
 539→    [showHUD],
 540→  );
 541→
 542→  const handleGridAction = useCallback(
 543→    (index: number) => {
 544→      const color = filteredColors[index];
 545→      if (color) {
 546→        handleCopyColor(color);
 547→      }
 548→    },
 549→    [
 550→      filteredColors,
 551→      handleCopyColor,
 552→    ],
 553→  );
 554→
 555→  const handleSnippetSubmit = useCallback(
 556→    (form: SnippetFormState) => {
 557→      showToast({
 558→        style: 'success',
 559→        title: 'Snippet Created',
 560→        message: form.name,
 561→      });
 562→      pop();
 563→    },
 564→    [
 565→      showToast,
 566→      pop,
 567→    ],
 568→  );
 569→
