  keyword: string;
  snippet: string;
  category: string;
  tags: string[];
  isShared: boolean;
  expiresAt: string;
}

const INITIAL_SNIPPET_FORM: SnippetFormState = {
  name: '',
  keyword: '',
  snippet: '',
  category: 'general',
  tags: [],
  isShared: false,
  expiresAt: '',
};

const SNIPPET_TAGS = [
  {
    label: 'JavaScript',
    value: 'javascript',
  },
  {
    label: 'TypeScript',
    value: 'typescript',
  },
  {
    label: 'Python',
    value: 'python',
  },
  {
    label: 'React',
    value: 'react',
  },
  {
    label: 'CSS',
    value: 'css',
  },
  {
    label: 'HTML',
    value: 'html',
  },
  {
    label: 'Shell',
    value: 'shell',
  },
  {
    label: 'Markdown',
    value: 'markdown',
  },
];

const SNIPPET_CATEGORIES = [
  {
    label: 'General',
    value: 'general',
  },
  {
    label: 'Code',
    value: 'code',
  },
  {
    label: 'Email',
    value: 'email',
